<template>
    <div id="index">
        <div class="left"></div>
        <div class="right"></div>
        <div class="center-btn" @click="openDoor" v-show="showBtn">认识一下吧</div>
        <div class="center">
            <div id="me">我</div>
            <div class="img xtu-img">
                <img src="../assets/xtu.jpg" alt="">
            </div>
            <div class="img zjsj-img" v-show="showImg_01">
                <img src="../assets/zjsj.jpg" alt="">
            </div>
            <div class="content">
                <p v-for="(item, index) in content" :key="index">{{item}}</p>
            </div>
        </div>
    </div>
</template>

<script>
    import Velocity from 'velocity-animate'
    export default {
        name: 'index',
        data () {
            return {
                showBtn: true,
                showImg_01: false,
                content: [],
            }
        },
        mounted () {

        },
        methods: {
            _initAnime () {
                let that = this
                let t1 = this.$anime.timeline({
                    easing: 'easeInOutQuad',
                    duration: 750
                })
                t1.add({
                    targets: '.xtu-img',
                    width: 450,
                    height: 278,
                    duration: 3000,
                    complete: function () {
                        that.content = ['毕业院校：湘潭大学', '就读时间：2010-2014', '专业：土木工程']
                    }
                })
                .add({
                    targets: '.xtu-img',
                    left: '10%',
                    width: 170,
                    height: 96,
                    duration: 2000,
                    delay: 2000,
                    complete: function () {
                        that.content = []
                    }
                })
                .add({
                    targets: '#me',
                    left: '90%',
                    duration: 5000,
                    complete: function () {
                        that.showImg_01 = true
                    }
                })
                .add({
                    targets: '.zjsj-img',
                    width: 450,
                    height: 278,
                    duration: 3000,
                    complete: function () {
                        that.content = ['公司名称：中建三局装饰有限公司', '在职时间：2014.7 - 2015.5', '职位：施工员']
                    }
                })
                .add({
                    targets: '.zjsj-img',
                    left: '90%',
                    width: 170,
                    height: 96,
                    duration: 2000,
                    delay: 2000,
                    complete: function () {
                        that.content = []
                    }
                })
                .add({
                    targets: '#me',
                    left: '50%',
                    duration: 3000
                })
                .add({
                    targets: '#me',
                    keyframes: [
                        {translateY: -40},
                        {translateX: 250},
                        {translateY: 40},
                        {translateX: 0},
                        {translateY: 0}
                    ],
                    duration: 4000,
                    easing: 'easeOutElastic(1, .8)',
                    loop: 4
                })
            },
            openDoor () {
                let that = this
                let leftDom = document.getElementsByClassName('left')[0]
                let rightDom = document.getElementsByClassName('right')[0]
                that.showBtn = false
                this.$anime({
                    targets: '.center',
                    backgroundColor: '#FFF',
                    easing: 'easeInOutQuad',
                    duration: 3000
                })
                Velocity(leftDom, {
                    left: "-35%"
                }, {
                    duration: 3000,
                    complete: function () {
                        that._initAnime()
                    }
                })
                Velocity(rightDom, {
                    right: "-35%"
                }, {
                    duration: 3000
                })
            }
        }
    }
</script>

<style lang="less" scoped>
    #index {
        position: relative;
        width: 100%;
        height: 100%;
        .left {
            position: absolute;
            top: 0;
            left: 0;
            width: 50%;
            height: 100%;
            background-color: greenyellow;
            z-index: 99;
        }
        .right {
            position: absolute;
            right: 0;
            top: 0;
            width: 50%;
            height: 100%;
            background-color: goldenrod;
            z-index: 99;
        }
        .center-btn {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            width: 200px;
            height: 200px;
            background-color: pink;
            border-radius: 50%;
            line-height: 200px;
            text-align: center;
            font-size: 24px;
            cursor: pointer;
            z-index: 100;
        }
        .center {
            position: absolute;
            top: 0;
            left: 15%;
            right: 15%;
            bottom: 0;
            background-color: #000;
            #me {
                position: absolute;
                top: 10%;
                left: 5%;
                width: 50px;
                height: 50px;
                border-radius: 50%;
                background-color: rgb(24, 255, 116);
                line-height: 50px;
                text-align: center;
                font-size: 16px;
            }
            .img {
                position: absolute;
                top: 5%;
                left: 50%;
                transform: translateX(-50%);
                width: 1px;
                height: 1px;
                img {
                    width: 100%;
                    height: 100%;
                }
            }
            .content {
                position: absolute;
                bottom: 0;
                left: 0;
                width: 100%;
                height: 200px;
                padding: 10px;
                font-size: 20px;
                text-align: center;
                font-weight: 700;
            }
        }
    }
</style>